def searchRange(nums, target):
    def find(left):
        l, r, res = 0, len(nums)-1, -1
        while l <= r:
            m = (l+r)//2
            if nums[m] > target or (left and nums[m] == target): r = m - 1; res = m if nums[m] == target else res
            else: l = m + 1; res = m if not left and nums[m] == target else res
        return res
    return [find(True), find(False)]

